from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["real-work-fast-path-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Real Work Fast Path</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#123256,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:9px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:120px}.chip{display:inline-flex;border:1px solid var(--line);border-radius:999px;padding:5px 9px;color:var(--muted);font-size:12px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:430px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>Real Work Fast Path</h1><p class="muted">Mapa real de projetos, repos, conversas e primeiro teste no PC. Nada fictício: tudo fica ligado a grupos, fronts e evidência.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="load()">Atualizar</button><button onclick="firstPc()">Checklist PC</button></div></section><section class="panel"><h2>Criar trabalho real</h2><input id="hint" value="GOD_MODE" placeholder="Projeto/grupo: GOD_MODE, Baribudos website, ProVentil..."/><textarea id="request" placeholder="Pedido do Oner para iniciar trabalho real..."></textarea><div class="buttons"><button onclick="workRun()">Criar work run</button><button class="dark" onclick="classify()">Classificar texto</button></div></section><section class="panel"><h2>Ligar repo</h2><div class="grid"><input id="repo" placeholder="AndreVazao/baribudos-website"/><input id="repoHint" placeholder="Baribudos website"/><input id="front" placeholder="website/studio/backend/mobile"/></div><button onclick="linkRepo()">Ligar repo ao grupo</button></section><section class="panel"><h2>Ligar conversa</h2><div class="grid"><input id="convTitle" placeholder="Título da conversa"/><input id="provider" value="chatgpt"/><input id="convHint" placeholder="Baribudos Studio"/></div><textarea id="convSummary" placeholder="Resumo ou contexto da conversa"></textarea><button onclick="linkConversation()">Ligar conversa</button></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function show(x){qs('#out').textContent=JSON.stringify(x,null,2)}async function load(){show(await api('/api/real-work-fast-path/dashboard'))}async function firstPc(){show(await api('/api/real-work-fast-path/first-pc-fast-path'))}async function classify(){show(await api('/api/real-work-fast-path/classify-text',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({text:qs('#hint').value+' '+qs('#request').value})}))}async function workRun(){show(await api('/api/real-work-fast-path/create-work-run',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({project_hint:qs('#hint').value,operator_request:qs('#request').value||'Continuar trabalho real',selected_provider_ids:['chatgpt','claude','gemini']})}))}async function linkRepo(){show(await api('/api/real-work-fast-path/link-repo',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({repo_full_name:qs('#repo').value,project_hint:qs('#repoHint').value,front:qs('#front').value,evidence:'operator_cockpit_link'})}))}async function linkConversation(){show(await api('/api/real-work-fast-path/link-conversation',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:qs('#convTitle').value,provider:qs('#provider').value,project_hint:qs('#convHint').value,summary:qs('#convSummary').value,source_ref:'operator_cockpit_link'})}))}load()</script></body></html>
"""


@router.get('/app/real-work-fast-path', response_class=HTMLResponse)
async def real_work_fast_path_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/real-work-map', response_class=HTMLResponse)
async def real_work_map_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
